170→function paywallPage(book: PressyBookManifest, chapterSlug: string): string {
171→  const title = book.paywall?.price
172→    ? `${book.slug} — Purchase Required`
173→    : `${book.slug} — Access Required`
174→  const price = book.paywall?.price || ''
175→  const bookSlug = book.slug
176→  // Sanitize slugs for safe embedding in HTML (alphanumeric + hyphens only)
177→  const safeBookSlug = bookSlug.replace(/[^a-zA-Z0-9-]/g, '')
178→  const safeChapterSlug = chapterSlug.replace(/[^a-zA-Z0-9-]/g, '')
179→
180→  return `<!DOCTYPE html>
181→<html lang="en">
182→<head>
183→<meta charset="utf-8">
184→<meta name="viewport" content="width=device-width, initial-scale=1">
185→<title>${title}</title>
186→<style>
187→  * { box-sizing: border-box; margin: 0; padding: 0; }
188→  body {
189→    font-family: Georgia, 'Times New Roman', serif;
190→    color: #1a1a1a;
191→    background: #fff;
192→    display: flex;
193→    justify-content: center;
194→    align-items: center;
195→    min-height: 100vh;
196→    padding: 2rem;
197→  }
198→  .paywall {
199→    max-width: 420px;
200→    text-align: center;
201→  }
202→  .paywall h1 {
203→    font-size: 1.5rem;
204→    margin-bottom: 0.75rem;
205→  }
206→  .paywall p {
207→    color: #555;
208→    line-height: 1.6;
209→    margin-bottom: 1.25rem;
210→  }
211→  .paywall .cta {
212→    display: inline-block;
213→    padding: 0.75rem 1.75rem;
214→    background: #2563eb;
215→    color: #fff;
216→    font-size: 1rem;
217→    font-weight: 600;
218→    text-decoration: none;
219→    border-radius: 0.5rem;
220→    transition: opacity 0.15s;
221→  }
222→  .paywall .cta:hover { opacity: 0.85; }
223→  .recover-toggle {
224→    display: inline-block;
225→    margin-top: 1rem;
226→    background: none;
227→    border: none;
228→    font: inherit;
229→    font-size: 0.85rem;
230→    color: #2563eb;
231→    text-decoration: underline;
232→    cursor: pointer;
233→  }
234→  .recover-toggle:hover { opacity: 0.75; }
235→  .recover-form {
236→    display: none;
237→    flex-wrap: wrap;
238→    gap: 0.5rem;
239→    margin-top: 0.75rem;
240→    justify-content: center;
241→  }
242→  .recover-form.visible { display: flex; }
243→  .recover-form input {
244→    flex: 1;
245→    min-width: 180px;
246→    padding: 0.5rem 0.75rem;
247→    font: inherit;
248→    font-size: 0.9rem;
249→    border: 1.5px solid #e5e5e5;
250→    border-radius: 0.375rem;
251→  }
252→  .recover-form button {
253→    padding: 0.5rem 1rem;
254→    font: inherit;
255→    font-size: 0.9rem;
256→    font-weight: 600;
257→    background: #2563eb;
258→    color: #fff;
259→    border: none;
260→    border-radius: 0.375rem;
261→    cursor: pointer;
262→  }
263→  .recover-form button:hover { opacity: 0.85; }
264→  .recover-form button:disabled { opacity: 0.6; cursor: not-allowed; }
265→  .msg { margin-top: 0.75rem; font-size: 0.85rem; }
266→  .msg.success { color: #2563eb; }
267→  .msg.error { color: #dc2626; }
268→  .hidden { display: none; }
269→</style>
270→</head>
271→<body>
272→<div class="paywall">
273→  <div id="loading">Checking access&hellip;</div>
274→  <div id="content" class="hidden">
275→    <h1>${title}</h1>
276→    <p>This chapter requires purchase to read.</p>
277→    <a class="cta" href="/api/checkout?book=${safeBookSlug}">Purchase${price ? ' — ' + price : ''}</a>
278→    <br>
279→    <button class="recover-toggle" id="recoverBtn">Already purchased?</button>
280→    <form class="recover-form" id="recoverForm">
281→      <input type="email" placeholder="Email address" required id="recoverEmail">
282→      <button type="submit" id="recoverSubmit">Send Recovery Link</button>
283→    </form>
284→    <div id="recoverMsg" class="msg hidden"></div>
285→  </div>
286→</div>
287→<script>
288→(function() {
289→  var bookSlug = "${safeBookSlug}";
290→  var chapterSlug = "${safeChapterSlug}";
291→
292→  // Check auth status — if authorized, fetch the real chapter directly.
293→  // A regular fetch() has mode "cors"/"same-origin" (not "navigate"), so it
294→  // bypasses the SW's NavigationRoute and goes straight to the origin with cookies.
295→  // This avoids the infinite-reload loop caused by the SW re-serving the cached paywall.
296→  fetch("/api/auth/status?book=" + encodeURIComponent(bookSlug))
297→    .then(function(r) { return r.json(); })
298→    .then(function(data) {
299→      if (data.authorized) {
300→        // Clear stale SW caches for this book (fire-and-forget)
301→        if (typeof caches !== "undefined") {
302→          ["pressy-pages", "pressy-static"].forEach(function(name) {
303→            caches.open(name).then(function(c) {
304→              c.keys().then(function(keys) {
305→                keys.forEach(function(k) {
306→                  if (k.url.includes("/books/" + bookSlug)) c.delete(k);
307→                });
308→              });
309→            });
310→          });
311→        }
312→        // Fetch the real chapter HTML directly (bypasses SW)
313→        fetch(location.href, { credentials: "include" })
314→          .then(function(r) {
315→            if (r.ok) return r.text();
316→            throw new Error("not ok");
317→          })
318→          .then(function(html) {
319→            document.open();
320→            document.write(html);
321→            document.close();
322→          })
323→          .catch(function() { showPaywall(); });
324→      } else {
325→        showPaywall();
326→      }
327→    })
328→    .catch(function() { showPaywall(); });
329→
330→  function showPaywall() {
331→    document.getElementById("loading").classList.add("hidden");
332→    document.getElementById("content").classList.remove("hidden");
333→  }
334→
335→  // Recover link toggle
336→  document.getElementById("recoverBtn").addEventListener("click", function() {
337→    document.getElementById("recoverForm").classList.toggle("visible");
338→    this.style.display = "none";
339→  });
340→
341→  // Recover form submit
342→  document.getElementById("recoverForm").addEventListener("submit", function(e) {
343→    e.preventDefault();
344→    var email = document.getElementById("recoverEmail").value;
345→    var btn = document.getElementById("recoverSubmit");
346→    var msg = document.getElementById("recoverMsg");
347→    btn.disabled = true;
348→    btn.textContent = "Sending\\u2026";
349→    fetch("/api/auth/recover", {
350→      method: "POST",
351→      headers: { "Content-Type": "application/json" },
352→      body: JSON.stringify({ email: email, book: bookSlug })
353→    })
354→    .then(function(r) {
355→      msg.classList.remove("hidden", "error", "success");
356→      if (r.ok) {
357→        msg.classList.add("success");
358→        msg.textContent = "Check your email for a recovery link.";
359→        document.getElementById("recoverForm").classList.remove("visible");
360→      } else {
361→        msg.classList.add("error");
362→        msg.textContent = "Something went wrong. Please try again.";
363→        btn.disabled = false;
364→        btn.textContent = "Send Recovery Link";
365→      }
366→    })
367→    .catch(function() {
368→      msg.classList.remove("hidden", "error", "success");
369→      msg.classList.add("error");
370→      msg.textContent = "Something went wrong. Please try again.";
371→      btn.disabled = false;
372→      btn.textContent = "Send Recovery Link";
373→    });
374→  });
375→})();
376→</script>
377→</body>
378→</html>`
379→}
