  1→import { useSignal } from '@preact/signals'
  2→import { useRef, useEffect } from 'preact/hooks'
  3→
  4→export function TextShare() {
  5→  const isVisible = useSignal(false)
  6→  const position = useSignal({ x: 0, y: 0 })
  7→  const selectedText = useSignal('')
  8→  const buttonRef = useRef<HTMLDivElement>(null)
  9→
 10→  useEffect(() => {
 11→    const handleSelectionChange = () => {
 12→      const selection = window.getSelection()
 13→      if (!selection || selection.isCollapsed) {
 14→        isVisible.value = false
 15→        return
 16→      }
 17→
 18→      const text = selection.toString().trim()
 19→      if (text.length < 5) {
 20→        isVisible.value = false
 21→        return
 22→      }
 23→
 24→      selectedText.value = text
 25→
 26→      // Position the share button above the selection
 27→      const range = selection.getRangeAt(0)
 28→      const rect = range.getBoundingClientRect()
 29→
 30→      position.value = {
 31→        x: rect.left + rect.width / 2,
 32→        y: rect.top - 10,
 33→      }
 34→      isVisible.value = true
 35→    }
 36→
 37→    document.addEventListener('selectionchange', handleSelectionChange)
 38→    document.addEventListener('mouseup', handleSelectionChange)
 39→
 40→    return () => {
 41→      document.removeEventListener('selectionchange', handleSelectionChange)
 42→      document.removeEventListener('mouseup', handleSelectionChange)
 43→    }
 44→  }, [])
 45→
 46→  const generateShareUrl = () => {
 47→    // Use Text Fragments API for direct linking
 48→    const encodedText = encodeURIComponent(selectedText.value)
 49→    const url = new URL(window.location.href)
 50→    url.hash = `:~:text=${encodedText}`
 51→    return url.toString()
 52→  }
 53→
 54→  const handleShare = async () => {
 55→    const url = generateShareUrl()
 56→    const text = `"${selectedText.value}"`
 57→
 58→    // Try Web Share API first
 59→    if (navigator.share) {
 60→      try {
 61→        await navigator.share({
 62→          text,
 63→          url,
 64→        })
 65→        isVisible.value = false
 66→        return
 67→      } catch (err) {
 68→        // User cancelled or share failed, fall through to clipboard
 69→      }
 70→    }
 71→
 72→    // Fallback to clipboard
 73→    try {
 74→      await navigator.clipboard.writeText(`${text}\n\n${url}`)
 75→      // Show copied feedback
 76→      if (buttonRef.current) {
 77→        buttonRef.current.classList.add('copied')
 78→        setTimeout(() => {
 79→          buttonRef.current?.classList.remove('copied')
 80→        }, 2000)
 81→      }
 82→    } catch (err) {
 83→      console.error('Failed to copy to clipboard:', err)
 84→    }
 85→  }
 86→
 87→  const handleCopyLink = async () => {
 88→    const url = generateShareUrl()
 89→    try {
 90→      await navigator.clipboard.writeText(url)
 91→      if (buttonRef.current) {
 92→        buttonRef.current.classList.add('copied')
 93→        setTimeout(() => {
 94→          buttonRef.current?.classList.remove('copied')
 95→        }, 2000)
 96→      }
 97→    } catch (err) {
 98→      console.error('Failed to copy link:', err)
 99→    }
100→  }
101→
102→  if (!isVisible.value) return null
103→
104→  return (
105→    <div
106→      ref={buttonRef}
107→      class="pressy-text-share"
108→      style={{
109→        left: `${position.value.x}px`,
110→        top: `${position.value.y}px`,
111→      }}
112→    >
113→      <button
114→        class="pressy-share-btn"
115→        onClick={handleShare}
116→        aria-label="Share selected text"
117→        title="Share quote"
118→      >
119→        <svg width="18" height="18" viewBox="0 0 24 24" fill="currentColor">
120→          <path d="M18 16.08c-.76 0-1.44.3-1.96.77L8.91 12.7c.05-.23.09-.46.09-.7s-.04-.47-.09-.7l7.05-4.11c.54.5 1.25.81 2.04.81 1.66 0 3-1.34 3-3s-1.34-3-3-3-3 1.34-3 3c0 .24.04.47.09.7L8.04 9.81C7.5 9.31 6.79 9 6 9c-1.66 0-3 1.34-3 3s1.34 3 3 3c.79 0 1.5-.31 2.04-.81l7.12 4.16c-.05.21-.08.43-.08.65 0 1.61 1.31 2.92 2.92 2.92s2.92-1.31 2.92-2.92-1.31-2.92-2.92-2.92z" />
121→        </svg>
122→      </button>
123→
124→      <button
125→        class="pressy-copy-link-btn"
126→        onClick={handleCopyLink}
127→        aria-label="Copy link to selected text"
128→        title="Copy link"
129→      >
130→        <svg width="18" height="18" viewBox="0 0 24 24" fill="currentColor">
131→          <path d="M3.9 12c0-1.71 1.39-3.1 3.1-3.1h4V7H7c-2.76 0-5 2.24-5 5s2.24 5 5 5h4v-1.9H7c-1.71 0-3.1-1.39-3.1-3.1zM8 13h8v-2H8v2zm9-6h-4v1.9h4c1.71 0 3.1 1.39 3.1 3.1s-1.39 3.1-3.1 3.1h-4V17h4c2.76 0 5-2.24 5-5s-2.24-5-5-5z" />
132→        </svg>
133→      </button>
134→
135→      <style>{`
136→        .pressy-text-share {
137→          position: fixed;
138→          transform: translate(-50%, -100%);
139→          display: flex;
140→          gap: 0.25rem;
141→          background: var(--color-bg);
142→          border: 1px solid var(--color-border);
143→          border-radius: 0.5rem;
144→          padding: 0.25rem;
145→          box-shadow: var(--shadow-md);
146→          z-index: 1000;
147→        }
148→
149→        .pressy-text-share::after {
150→          content: '';
151→          position: absolute;
152→          bottom: -6px;
153→          left: 50%;
154→          transform: translateX(-50%);
155→          border-left: 6px solid transparent;
156→          border-right: 6px solid transparent;
157→          border-top: 6px solid var(--color-bg);
158→        }
159→
160→        .pressy-share-btn,
161→        .pressy-copy-link-btn {
162→          display: flex;
163→          align-items: center;
164→          justify-content: center;
165→          width: 2rem;
166→          height: 2rem;
167→          border: none;
168→          background: transparent;
169→          color: var(--color-text-muted);
170→          cursor: pointer;
171→          border-radius: 0.25rem;
172→          transition: background 0.15s, color 0.15s;
173→        }
174→
175→        .pressy-share-btn:hover,
176→        .pressy-copy-link-btn:hover {
177→          background: var(--color-bg-muted);
178→          color: var(--color-text);
179→        }
180→
181→        .pressy-text-share.copied .pressy-copy-link-btn {
182→          color: var(--color-accent);
183→        }
184→      `}</style>
185→    </div>
186→  )
187→}
