 11→// ── Offline Footer Icon ───────────────────────────────────────
 12→
 13→export function OfflineFooterIcon({ offlineProps }: { offlineProps?: OfflineProps }) {
 14→  if (!offlineProps) return null;
 15→
 16→  const {
 17→    bookSlug,
 18→    chapterUrls,
 19→    cachedBooks,
 20→    onDownload,
 21→    onRemove,
 22→  } = offlineProps;
 23→
 24→  // Read signal .value directly in render — @preact/signals auto-subscribes
 25→  // and re-renders this component when the underlying signal changes.
 26→  const isCached = cachedBooks.value.has(bookSlug);
 27→
 28→  // Check isCached FIRST (matching DownloadBook's order). The download function
 29→  // optimistically marks the book as cached immediately, so isCached becomes true
 30→  // at the same time as isDownloading. Checking isCached first means we show the
 31→  // cached icon right away while the SW downloads in the background.
 32→  if (isCached) {
 33→    return (
 34→      <button
 35→        class="pressy-offline-icon pressy-offline-icon--cached"
 36→        onClick={(e: MouseEvent) => {
 37→          e.stopPropagation();
 38→          onRemove(bookSlug);
 39→        }}
 40→        aria-label="Available offline. Click to remove."
 41→        title="Available offline. Click to remove."
 42→      >
 43→        <svg
 44→          viewBox="0 0 24 24"
 45→          fill="none"
 46→          stroke="currentColor"
 47→          stroke-width="1.5"
 48→          stroke-linecap="round"
 49→          stroke-linejoin="round"
 50→          width="18"
 51→          height="18"
 52→        >
 53→          <path d="M18 10h-1.26A8 8 0 1 0 9 20h9a5 5 0 0 0 0-10z" />
 54→          <polyline points="9 15 12 18 15 15" />
 55→          <line x1="12" y1="12" x2="12" y2="18" />
 56→        </svg>
 57→        <svg
 58→          class="pressy-offline-check"
 59→          viewBox="0 0 24 24"
 60→          fill="currentColor"
 61→          width="10"
 62→          height="10"
 63→        >
 64→          <path d="M9 16.17L4.83 12l-1.42 1.41L9 19 21 7l-1.41-1.41L9 16.17z" />
 65→        </svg>
 66→      </button>
 67→    );
 68→  }
 69→
 70→  return (
 71→    <button
 72→      class="pressy-offline-icon"
 73→      onClick={(e: MouseEvent) => {
 74→        e.stopPropagation();
 75→        onDownload(bookSlug, chapterUrls);
 76→      }}
 77→      aria-label="Download for offline reading"
 78→      title="Download for offline reading"
 79→    >
 80→      <svg
 81→        viewBox="0 0 24 24"
 82→        fill="none"
 83→        stroke="currentColor"
 84→        stroke-width="1.5"
 85→        stroke-linecap="round"
 86→        stroke-linejoin="round"
 87→        width="18"
 88→        height="18"
 89→      >
 90→        <path d="M18 10h-1.26A8 8 0 1 0 9 20h9a5 5 0 0 0 0-10z" />
 91→        <polyline points="9 15 12 18 15 15" />
 92→        <line x1="12" y1="12" x2="12" y2="18" />
 93→      </svg>
 94→    </button>
 95→  );
 96→}
