 98→// ── Scroll Reader ────────────────────────────────────────────
 99→
100→export interface ScrollReaderProps {
101→  children: ComponentChildren;
102→  bookTitle?: string;
103→  prevChapter?: { slug: string; title: string };
104→  nextChapter?: { slug: string; title: string };
105→  showDropCap: boolean;
106→  onSaveProgress?: (data: ProgressData) => void;
107→  onRestoreProgress?: () => Promise<ProgressData | null>;
108→  allChapters?: Array<{ slug: string; title: string; wordCount?: number }>;
109→  bookBasePath?: string;
110→  currentChapterSlug?: string;
111→  offlineProps?: OfflineProps;
112→  bookmarkProps?: BookmarkProps;
113→}
114→
115→export function ScrollReader({
116→  children,
117→  bookTitle,
118→  prevChapter,
119→  nextChapter,
120→  showDropCap,
121→  onSaveProgress,
122→  onRestoreProgress,
123→  allChapters,
124→  bookBasePath,
125→  currentChapterSlug,
126→  offlineProps,
127→  bookmarkProps,
128→}: ScrollReaderProps) {
129→  const saveTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
130→
131→  // Footer visibility
132→  const [footerVisible, setFooterVisible] = useState(false);
133→  const footerTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
134→  const [settingsOpen, setSettingsOpen] = useState(false);
135→  const [tocOpen, setTocOpen] = useState(false);
136→  const [bookmarksOpen, setBookmarksOpen] = useState(false);
137→
138→  const showFooterTemporarily = useCallback(() => {
139→    setFooterVisible(true);
140→    if (footerTimerRef.current) clearTimeout(footerTimerRef.current);
141→    footerTimerRef.current = setTimeout(() => setFooterVisible(false), 3000);
142→  }, []);
143→
144→  // Settings state
145→  const [activeTheme, setActiveTheme] = useState<string>(() => {
146→    if (typeof localStorage !== "undefined") {
147→      return localStorage.getItem("pressy-theme") || "light";
148→    }
149→    return "light";
150→  });
151→  const [fontScale, setFontScale] = useState<number>(() => {
152→    if (typeof localStorage !== "undefined") {
153→      const saved = localStorage.getItem("pressy-font-size");
154→      return saved ? parseFloat(saved) : 1.0;
155→    }
156→    return 1.0;
157→  });
158→
159→  const applyFontScale = useCallback((scale: number) => {
160→    if (scale === 1.0) {
161→      document.documentElement.style.removeProperty("--font-size-base");
162→    } else {
163→      document.documentElement.style.setProperty(
164→        "--font-size-base",
165→        `calc(clamp(1rem, 0.875rem + 0.5vw, 1.25rem) * ${scale})`
166→      );
167→    }
168→  }, []);
169→
170→  useEffect(() => {
171→    if (fontScale !== 1.0) {
172→      applyFontScale(fontScale);
173→    }
174→  }, []);
175→
176→  const handleThemeChange = useCallback((theme: string) => {
177→    setActiveTheme(theme);
178→    localStorage.setItem("pressy-theme", theme);
179→    const resolved =
180→      theme === "system"
181→        ? window.matchMedia("(prefers-color-scheme: dark)").matches
182→          ? "dark"
183→          : "light"
184→        : theme;
185→    document.documentElement.setAttribute("data-theme", resolved);
186→  }, []);
187→
188→  const handleFontSizeChange = useCallback(
189→    (delta: number) => {
190→      setFontScale((prev) => {
191→        const next =
192→          Math.round(Math.max(0.8, Math.min(1.5, prev + delta)) * 10) / 10;
193→        localStorage.setItem("pressy-font-size", String(next));
194→        applyFontScale(next);
195→        return next;
196→      });
197→    },
198→    [applyFontScale]
199→  );
200→
201→  // Toggle footer on tap
202→  const handleReaderClick = useCallback(
203→    (e: MouseEvent) => {
204→      const target = e.target as HTMLElement;
205→      if (
206→        target.closest(
207→          ".pressy-page-footer, .pressy-toc-backdrop, .pressy-toc-toggle, .pressy-bookmarks-panel, .pressy-bookmarks-toggle"
208→        )
209→      )
210→        return;
211→      if (target.closest('a, button, input, select, textarea, [role="button"]'))
212→        return;
213→
214→      if (settingsOpen || tocOpen || bookmarksOpen) {
215→        setSettingsOpen(false);
216→        setTocOpen(false);
217→        setBookmarksOpen(false);
218→        return;
219→      }
220→
221→      if (footerVisible) {
222→        setFooterVisible(false);
223→        if (footerTimerRef.current) clearTimeout(footerTimerRef.current);
224→      } else {
225→        showFooterTemporarily();
226→      }
227→    },
228→    [footerVisible, settingsOpen, tocOpen, bookmarksOpen, showFooterTemporarily]
229→  );
230→
231→  // Restore scroll position on mount
232→  useEffect(() => {
233→    if (!onRestoreProgress) return;
234→    onRestoreProgress().then((data) => {
235→      if (data && data.scrollPosition > 0) {
236→        window.scrollTo(0, data.scrollPosition);
237→      }
238→    });
239→  }, []);
240→
241→  // Save scroll position (debounced)
242→  useEffect(() => {
243→    if (!onSaveProgress) return;
244→
245→    const handleScroll = () => {
246→      if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
247→      saveTimerRef.current = setTimeout(() => {
248→        onSaveProgress({
249→          page: 0,
250→          totalPages: 0,
251→          scrollPosition: window.scrollY,
252→        });
253→      }, 500);
254→    };
255→
256→    window.addEventListener("scroll", handleScroll, { passive: true });
257→    return () => {
258→      window.removeEventListener("scroll", handleScroll);
259→      if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
260→    };
261→  }, [onSaveProgress]);
262→
263→  // Save on page unload
264→  useEffect(() => {
265→    if (!onSaveProgress) return;
266→
267→    const handleUnload = () => {
268→      onSaveProgress({
269→        page: 0,
270→        totalPages: 0,
271→        scrollPosition: window.scrollY,
272→      });
273→    };
274→
275→    const handleVisibilityChange = () => {
276→      if (document.visibilityState === "hidden") handleUnload();
277→    };
278→
279→    window.addEventListener("beforeunload", handleUnload);
280→    document.addEventListener("visibilitychange", handleVisibilityChange);
281→    return () => {
282→      window.removeEventListener("beforeunload", handleUnload);
283→      document.removeEventListener("visibilitychange", handleVisibilityChange);
284→    };
285→  }, [onSaveProgress]);
286→
287→  return (
288→    <div class="pressy-reader" onClick={handleReaderClick}>
289→      <main class="pressy-reader-main">
290→        <article
291→          class={`pressy-prose ${showDropCap ? "" : "no-drop-cap"}`}
292→          data-drop-cap={showDropCap}
293→        >
294→          {children}
295→        </article>
296→      </main>
297→
298→      <TextShare />
299→      <Navigation prev={prevChapter} next={nextChapter} />
300→      <OfflineIndicator />
301→
302→      {/* TOC drawer overlay */}
303→      {tocOpen && allChapters && (
304→        <div
305→          class="pressy-toc-backdrop pressy-toc-backdrop--scroll"
306→          onClick={(e: MouseEvent) => {
307→            e.stopPropagation();
308→            setTocOpen(false);
309→          }}
310→        >
311→          <div
312→            class="pressy-toc-drawer"
313→            onClick={(e: MouseEvent) => e.stopPropagation()}
314→          >
315→            <div class="pressy-toc-header">
316→              <span class="pressy-toc-title">Contents</span>
317→              <button
318→                class="pressy-toc-close"
319→                onClick={(e: MouseEvent) => {
320→                  e.stopPropagation();
