 1→export function formatRelativeTime(timestamp: number): string {
 2→  const seconds = Math.floor((Date.now() - timestamp) / 1000);
 3→  if (seconds < 60) return "just now";
 4→  const minutes = Math.floor(seconds / 60);
 5→  if (minutes < 60) return `${minutes}m ago`;
 6→  const hours = Math.floor(minutes / 60);
 7→  if (hours < 24) return `${hours}h ago`;
 8→  const days = Math.floor(hours / 24);
 9→  if (days < 30) return `${days}d ago`;
10→  const months = Math.floor(days / 30);
11→  return `${months}mo ago`;
12→}
