  1→import { useSignal } from '@preact/signals'
  2→import { useEffect } from 'preact/hooks'
  3→
  4→const CACHED_BOOKS_KEY = 'pressy-cached-books'
  5→
  6→function readCachedBooks(): Set<string> {
  7→  try {
  8→    const stored = localStorage.getItem(CACHED_BOOKS_KEY)
  9→    if (stored) return new Set(JSON.parse(stored))
 10→  } catch {}
 11→  return new Set()
 12→}
 13→
 14→export interface DownloadBookProps {
 15→  bookSlug: string
 16→  chapterUrls: string[]
 17→  /** Reactive signal: set of cached book slugs */
 18→  cachedBooks: { value: Set<string> }
 19→  /** Reactive signal: current download progress or null */
 20→  cacheProgress: { value: { bookSlug: string; current: number; total: number } | null }
 21→  /** Called to start downloading the book */
 22→  onDownload: (bookSlug: string, chapterUrls: string[]) => void
 23→  /** Called to remove the cached book */
 24→  onRemove: (bookSlug: string) => void
 25→}
 26→
 27→export function DownloadBook({
 28→  bookSlug,
 29→  chapterUrls,
 30→  cachedBooks,
 31→  cacheProgress,
 32→  onDownload,
 33→  onRemove,
 34→}: DownloadBookProps) {
 35→  // Check localStorage directly for initial state, and also track the signal
 36→  // for live updates (e.g. after downloading or removing).
 37→  const isCached = useSignal(readCachedBooks().has(bookSlug) || cachedBooks.value.has(bookSlug))
 38→  const isDownloading = useSignal(cacheProgress.value?.bookSlug === bookSlug)
 39→  const progress = useSignal<number | null>(null)
 40→
 41→  // Sync with external signals on each render
 42→  useEffect(() => {
 43→    const check = () => {
 44→      isCached.value = readCachedBooks().has(bookSlug) || cachedBooks.value.has(bookSlug)
 45→      isDownloading.value = cacheProgress.value?.bookSlug === bookSlug
 46→      const p = cacheProgress.value
 47→      progress.value = p && p.bookSlug === bookSlug
 48→        ? Math.round((p.current / p.total) * 100)
 49→        : null
 50→    }
 51→
 52→    // Poll briefly to catch signal updates (SW messages are async)
 53→    const interval = setInterval(check, 500)
 54→    check()
 55→    return () => clearInterval(interval)
 56→  }, [bookSlug])
 57→
 58→  if (isCached.value) {
 59→    return (
 60→      <div class="pressy-download-book">
 61→        <div class="pressy-download-status">
 62→          <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
 63→            <path d="M9 16.17L4.83 12l-1.42 1.41L9 19 21 7l-1.41-1.41L9 16.17z" />
 64→          </svg>
 65→          <span>Available offline</span>
 66→        </div>
 67→        <button
 68→          class="pressy-download-remove"
 69→          onClick={() => onRemove(bookSlug)}
 70→          aria-label="Remove offline copy"
 71→        >
 72→          Remove
 73→        </button>
 74→
 75→        <style>{STYLES}</style>
 76→      </div>
 77→    )
 78→  }
 79→
 80→  if (isDownloading.value) {
 81→    return (
 82→      <div class="pressy-download-book">
 83→        <div class="pressy-download-progress">
 84→          <div class="pressy-download-bar">
 85→            <div
 86→              class="pressy-download-bar-fill"
 87→              style={{ width: `${progress.value || 0}%` }}
 88→            />
 89→          </div>
 90→          <span class="pressy-download-percent">{progress.value || 0}%</span>
 91→        </div>
 92→
 93→        <style>{STYLES}</style>
 94→      </div>
 95→    )
 96→  }
 97→
 98→  return (
 99→    <div class="pressy-download-book">
100→      <button
101→        class="pressy-download-btn"
102→        onClick={() => onDownload(bookSlug, chapterUrls)}
103→        aria-label="Download for offline reading"
104→      >
105→        <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
106→          <path d="M19 9h-4V3H9v6H5l7 7 7-7zM5 18v2h14v-2H5z" />
107→        </svg>
108→        <span>Download for offline</span>
109→      </button>
110→
111→      <style>{STYLES}</style>
112→    </div>
113→  )
114→}
