 4→export function OfflineIndicator() {
 5→  const isOffline = useSignal(!navigator.onLine)
 6→  const isVisible = useSignal(false)
 7→
 8→  useEffect(() => {
 9→    const handleOnline = () => {
10→      isOffline.value = false
11→      // Show briefly when coming back online
12→      isVisible.value = true
13→      setTimeout(() => {
14→        isVisible.value = false
15→      }, 3000)
16→    }
17→
18→    const handleOffline = () => {
19→      isOffline.value = true
20→      isVisible.value = true
21→    }
22→
23→    window.addEventListener('online', handleOnline)
24→    window.addEventListener('offline', handleOffline)
25→
26→    return () => {
27→      window.removeEventListener('online', handleOnline)
28→      window.removeEventListener('offline', handleOffline)
29→    }
30→  }, [])
31→
32→  if (!isVisible.value) return null
33→
34→  return (
35→    <div class={`pressy-offline-indicator ${isOffline.value ? 'offline' : 'online'}`}>
36→      {isOffline.value ? (
37→        <>
38→          <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
39→            <path d="M23.64 7c-.45-.34-4.93-4-11.64-4-1.5 0-2.89.19-4.15.48L18.18 13.8 23.64 7zM3.41 1.31L2 2.72l2.05 2.05C1.91 5.76.59 6.82.36 7L12 21.5l3.91-4.87 3.32 3.32 1.41-1.41L3.41 1.31z" />
