  1→import { useSignal } from "@preact/signals";
  2→
  3→export interface PaywallProps {
  4→  bookSlug: string;
  5→  bookTitle: string;
  6→  previewChapters: number;
  7→  currentChapter: number;
  8→  onUnlock?: () => void;
  9→}
 10→
 11→export function Paywall({
 12→  bookSlug,
 13→  bookTitle,
 14→  previewChapters,
 15→  currentChapter,
 16→  onUnlock,
 17→}: PaywallProps) {
 18→  const email = useSignal("");
 19→  const isLoading = useSignal(false);
 20→  const error = useSignal("");
 21→  const isUnlocked = useSignal(false);
 22→
 23→  // Check if already unlocked
 24→  if (typeof window !== "undefined") {
 25→    const unlocked = localStorage.getItem(`pressy-unlocked-${bookSlug}`);
 26→    if (unlocked) {
 27→      isUnlocked.value = true;
 28→    }
 29→  }
 30→
 31→  if (isUnlocked.value) {
 32→    return null;
 33→  }
 34→
 35→  // Show paywall if past preview chapters
 36→  if (currentChapter <= previewChapters) {
 37→    return null;
 38→  }
 39→
 40→  const handleEmailSubmit = async (e: Event) => {
 41→    e.preventDefault();
 42→
 43→    if (!email.value || !email.value.includes("@")) {
 44→      error.value = "Please enter a valid email address";
 45→      return;
 46→    }
 47→
 48→    isLoading.value = true;
 49→    error.value = "";
 50→
 51→    try {
 52→      // In a real implementation, this would send to a backend
 53→      // For now, just unlock locally
 54→      await new Promise((resolve) => setTimeout(resolve, 1000));
 55→
 56→      localStorage.setItem(`pressy-unlocked-${bookSlug}`, "email");
 57→      localStorage.setItem(`pressy-email-${bookSlug}`, email.value);
 58→
 59→      isUnlocked.value = true;
 60→      onUnlock?.();
 61→    } catch (err) {
 62→      error.value = "Something went wrong. Please try again.";
 63→    } finally {
 64→      isLoading.value = false;
 65→    }
 66→  };
 67→
 68→  return (
 69→    <div class="pressy-paywall">
 70→      <div class="pressy-paywall-content">
 71→        <div class="pressy-paywall-icon">
 72→          <svg width="48" height="48" viewBox="0 0 24 24" fill="currentColor">
 73→            <path d="M18 8h-1V6c0-2.76-2.24-5-5-5S7 3.24 7 6v2H6c-1.1 0-2 .9-2 2v10c0 1.1.9 2 2 2h12c1.1 0 2-.9 2-2V10c0-1.1-.9-2-2-2zm-6 9c-1.1 0-2-.9-2-2s.9-2 2-2 2 .9 2 2-.9 2-2 2zm3.1-9H8.9V6c0-1.71 1.39-3.1 3.1-3.1 1.71 0 3.1 1.39 3.1 3.1v2z" />
 74→          </svg>
 75→        </div>
 76→
 77→        <h2 class="pressy-paywall-title">Continue Reading</h2>
 78→        <p class="pressy-paywall-description">
 79→          You've enjoyed the first {previewChapters} chapters of "{bookTitle}".
 80→          Enter your email to unlock the full book.
 81→        </p>
 82→
 83→        <form class="pressy-paywall-form" onSubmit={handleEmailSubmit}>
 84→          <input
 85→            type="email"
 86→            placeholder="Enter your email"
 87→            value={email.value}
 88→            onInput={(e) =>
 89→              (email.value = (e.target as HTMLInputElement).value)
 90→            }
 91→            class="pressy-paywall-input"
 92→            disabled={isLoading.value}
 93→          />
 94→          <button
 95→            type="submit"
 96→            class="pressy-paywall-button"
 97→            disabled={isLoading.value}
 98→          >
 99→            {isLoading.value ? "Unlocking..." : "Unlock Full Book"}
100→          </button>
101→        </form>
102→
103→        {error.value && <p class="pressy-paywall-error">{error.value}</p>}
104→
105→        <p class="pressy-paywall-note">
106→          We'll never share your email with anyone.
107→        </p>
108→      </div>
109→
110→      <style>{`
111→        .pressy-paywall {
112→          position: fixed;
113→          inset: 0;
114→          background: var(--color-overlay);
115→          display: flex;
116→          align-items: center;
117→          justify-content: center;
118→          z-index: 1000;
119→          padding: 1.5rem;
120→        }
121→
122→        .pressy-paywall-content {
123→          background: var(--color-bg);
124→          border-radius: 1rem;
125→          padding: 2.5rem;
126→          max-width: 400px;
127→          width: 100%;
128→          text-align: center;
129→        }
130→
131→        .pressy-paywall-icon {
132→          color: var(--color-accent);
133→          margin-bottom: 1.5rem;
134→        }
135→
136→        .pressy-paywall-title {
137→          font-size: var(--font-size-xl);
138→          font-weight: 600;
139→          margin-bottom: 0.75rem;
140→          color: var(--color-heading);
141→        }
142→
143→        .pressy-paywall-description {
144→          color: var(--color-text-muted);
145→          margin-bottom: 1.5rem;
146→          line-height: 1.5;
147→        }
148→
149→        .pressy-paywall-form {
150→          display: flex;
151→          flex-direction: column;
152→          gap: 0.75rem;
153→        }
154→
155→        .pressy-paywall-input {
156→          width: 100%;
157→          padding: 0.875rem 1rem;
158→          border: 1px solid var(--color-border);
159→          border-radius: 0.5rem;
160→          font-size: var(--font-size-base);
161→          background: var(--color-bg);
