196→          margin-top: 0.75rem;
197→        }
198→
199→        .pressy-paywall-note {
200→          font-size: var(--font-size-sm);
201→          color: var(--color-text-muted);
202→          margin-top: 1.5rem;
203→        }
204→      `}</style>
