208→function StartReadingCTA({ book }: { book: Book }) {
209→  if (book.chapters.length === 0) return null
210→
211→  const firstHref = `${basePath}/books/${book.slug}/${book.chapters[0].slug}`
212→
213→  // Synchronously check localStorage so the first render can already show
214→  // "Continue Reading" without waiting for IndexedDB.
215→  const initialTarget = (() => {
216→    try {
217→      const lastRead = localStorage.getItem('pressy-last-read')
218→      if (lastRead) {
219→        const { bookSlug, chapterSlug } = JSON.parse(lastRead)
220→        if (bookSlug === book.slug && book.chapters.some(ch => ch.slug === chapterSlug)) {
221→          return {
222→            label: 'Continue Reading',
223→            href: `${basePath}/books/${book.slug}/${chapterSlug}`,
224→          }
225→        }
226→      }
227→    } catch {
228→      // ignore
229→    }
230→    return { label: 'Start Reading', href: firstHref }
231→  })()
232→
233→  // Always render a visible button immediately. The async IndexedDB check
234→  // below may upgrade "Start Reading" → "Continue Reading", but the button
235→  // is never invisible — previously it started as null which meant any
236→  // failure in the async chain (blocked IDB upgrade, race condition, etc.)
237→  // left the CTA permanently missing.
238→  const [target, setTarget] = useState(initialTarget)
239→
240→  useEffect(() => {
241→    // IndexedDB has per-chapter progress that may be more accurate than
242→    // the single localStorage entry. Try to find an in-progress chapter.
243→    getAllReadingProgress().then((allProgress) => {
244→      const progressMap = new Map(allProgress.map((p) => [p.chapterSlug, p]))
245→
246→      let furthestInProgress: Chapter | null = null
247→      for (const ch of book.chapters) {
248→        const p = progressMap.get(ch.slug)
249→        if (!p) continue
250→        const completed = p.totalPages > 0 && p.page >= p.totalPages - 1
251→        if (!completed && p.page > 0) {
252→          furthestInProgress = ch
253→        }
254→      }
255→
256→      if (furthestInProgress) {
257→        setTarget({
258→          label: 'Continue Reading',
259→          href: `${basePath}/books/${book.slug}/${furthestInProgress.slug}`,
260→        })
261→      }
262→    }).catch(() => {
263→      // IndexedDB unavailable — keep the synchronously-determined target
264→    })
265→  }, [book])
266→
267→  return (
268→    <a href={target.href} class="pressy-cta">
269→      {target.label}
270→    </a>
271→  )
272→}
