431→  useEffect(() => {
432→    const article = articleRef.current;
433→    const viewport = viewportRef.current;
434→    if (!article || !viewport) return;
435→
436→    const viewportRect = viewport.getBoundingClientRect();
437→
438→    const focusable = article.querySelectorAll<HTMLElement>(
439→      "a[href], button, input, select, textarea, [tabindex]"
440→    );
441→
442→    focusable.forEach((el) => {
443→      const elRect = el.getBoundingClientRect();
444→      const onCurrentPage =
445→        elRect.left >= viewportRect.left - 1 &&
446→        elRect.right <= viewportRect.right + 1;
447→
448→      if (onCurrentPage) {
449→        const original = el.getAttribute("data-original-tabindex");
450→        if (original !== null) {
