799→function renderChapterPage(
800→  manifest: ContentManifest,
801→  route: string,
802→  Content: ComponentType,
803→  paginationMode?: 'scroll' | 'paginated',
804→  chapterMapData?: ChapterMapData,
805→) {
806→  const parts = route.split('/')
807→  const bookSlug = parts[2]
808→  const chapterSlug = parts[3]
809→  const book = manifest.books.find((b: Book) => b.slug === bookSlug)
810→  const chapterIdx = book ? book.chapters.findIndex((c: Chapter) => c.slug === chapterSlug) : -1
811→  const chapter = book?.chapters[chapterIdx]
812→  const chapterPath = (ch: Chapter) => `${basePath}/books/${bookSlug}/${ch.slug}`
813→  const prevChapter = book && chapterIdx > 0
814→    ? { slug: chapterPath(book.chapters[chapterIdx - 1]), title: book.chapters[chapterIdx - 1].title }
815→    : book
816→      ? { slug: `${basePath}/books/${bookSlug}`, title: book.metadata.title }
817→      : undefined
818→  const nextChapter = book && chapterIdx >= 0 && chapterIdx < book.chapters.length - 1
819→    ? { slug: chapterPath(book.chapters[chapterIdx + 1]), title: book.chapters[chapterIdx + 1].title }
820→    : book
821→      ? { slug: `${basePath}/books/${bookSlug}`, title: book.metadata.title }
822→      : undefined
823→
824→  const MDXContent = Content as ComponentType<{ components?: Record<string, unknown> }>
825→
826→  if (!book) {
