828→      <Reader
829→        title={chapter?.title || chapterSlug}
830→        prevChapter={prevChapter}
831→        nextChapter={nextChapter}
832→        paginationMode={paginationMode}
833→      >
834→        <MDXContent components={useMDXComponents()} />
835→      </Reader>
836→    )
837→  }
838→
839→  return (
840→    <ChapterReaderWithProgress
841→      book={book}
842→      chapterSlug={chapterSlug}
843→      chapter={chapter}
844→      prevChapter={prevChapter}
845→      nextChapter={nextChapter}
846→      paginationMode={paginationMode}
847→      Content={MDXContent}
848→      chapterMapData={chapterMapData}
849→    />

