1110→// Compute the base path by comparing the known route to the actual URL
1111→// e.g. URL="/pressy/pr-preview/pr-4/books/flatland" with route="/books/flatland"
1112→// yields basePath="/pressy/pr-preview/pr-4"
1113→function getBasePath(route: string): string {
1114→  const pathname = window.location.pathname
1115→  // Remove trailing slash for comparison
1116→  const cleanPath = pathname.endsWith('/') ? pathname.slice(0, -1) : pathname
1117→  const cleanRoute = route.endsWith('/') ? route.slice(0, -1) : route
1118→  if (cleanRoute === '' || cleanRoute === '/') {
1119→    // Home page: strip /index.html or trailing slash
1120→    return cleanPath.replace(/\/index\.html$/, '') || ''
1121→  }
1122→  const idx = cleanPath.indexOf(cleanRoute)
1123→  if (idx > 0) {
1124→    return cleanPath.slice(0, idx)
1125→  }
1126→  return ''
1127→}
