149→      const filtered = all
150→        .filter(b => b.bookSlug === bookSlug)
151→        .sort((a, b) => b.createdAt - a.createdAt)
152→      resolve(filtered)
153→    }
154→    request.onerror = () => reject(request.error)
155→  })
156→}
