173→export function setTheme(theme: 'light' | 'dark' | 'sepia' | 'system'): void {
174→  currentTheme.value = theme
175→  localStorage.setItem('pressy-theme', theme)
176→  const resolved = theme === 'system' ? resolveSystemTheme() : theme
177→  document.documentElement.setAttribute('data-theme', resolved)
178→}
