180→function loadTheme(): void {
181→  const saved = localStorage.getItem('pressy-theme') as 'light' | 'dark' | 'sepia' | 'system' | null
182→  if (saved) {
183→    setTheme(saved)
184→  } else if (window.matchMedia('(prefers-color-scheme: dark)').matches) {
185→    setTheme('dark')
186→  }
187→
188→  // Listen for OS theme changes so "system" mode updates live
189→  window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change', () => {
190→    if (currentTheme.value === 'system') {
191→      document.documentElement.setAttribute('data-theme', resolveSystemTheme())
192→    }
193→  })
194→}
