 12→const NO_CACHE = { 'Cache-Control': 'no-store' }
 13→const SECURITY_HEADERS = {
 14→  'X-Content-Type-Options': 'nosniff',
 15→  'X-Frame-Options': 'DENY',
 16→}
 17→
 18→let cachedManifest: PressyManifest | null = null
 19→
 20→async function loadManifest(env: Env): Promise<PressyManifest> {
 21→  if (cachedManifest) return cachedManifest
 22→
 23→  const response = await env.ASSETS.fetch(new Request('https://placeholder/_pressy/manifest.json'))
 24→  if (!response.ok) {
 25→    throw new Error(`Failed to load _pressy/manifest.json: ${response.status}`)
 26→  }
 27→  cachedManifest = (await response.json()) as PressyManifest
 28→  return cachedManifest
 29→}
