381→function missingEnvError(...names: string[]): Response {
382→  const hint = names.map((n) => `wrangler pages secret put ${n}`).join(', ')
383→  return new Response(
384→    JSON.stringify({ error: `Missing required environment variable(s): ${names.join(', ')}. Set via: ${hint}` }),
385→    { status: 500, headers: { 'Content-Type': 'application/json', ...NO_CACHE } },
386→  )
387→}
