389→// Route → allowed method(s) mapping
390→const ROUTE_METHODS: Record<string, string> = {
391→  '/api/checkout': 'GET',
392→  '/api/stripe-webhook': 'POST',
393→  '/api/auth/callback': 'GET',
394→  '/api/auth/status': 'GET',
395→  '/api/auth/recover': 'POST',
396→  '/api/auth/verify': 'GET',
397→}
398→
399→async function handleApiRoute(
400→  request: Request,
401→  env: Env,
402→  pathname: string,
403→  url: URL,
404→  options: PressyMiddlewareOptions,
405→): Promise<Response> {
406→  // Method enforcement
407→  const allowedMethod = ROUTE_METHODS[pathname]
408→  if (allowedMethod && request.method !== allowedMethod) {
409→    return methodNotAllowed()
410→  }
411→
412→  // Rate limiting for auth endpoints
413→  if (pathname.startsWith('/api/auth/')) {
414→    const ip = getClientIp(request)
415→    const blocked = await rateLimit(env.PRESSY_KV, `auth:${ip}`, 60, 60)
416→    if (blocked) {
417→      return new Response('Too many requests', { status: 429, headers: NO_CACHE })
418→    }
419→  }
420→
421→  let manifest: PressyManifest
422→  try {
423→    manifest = await loadManifest(env)
424→  } catch {
425→    return new Response('Manifest not found', { status: 500 })
426→  }
427→
428→  // GET /api/checkout?book=SLUG
429→  if (pathname === '/api/checkout') {
430→    if (!env.STRIPE_SECRET_KEY) return missingEnvError('STRIPE_SECRET_KEY')
431→    const bookSlug = url.searchParams.get('book')
432→    if (!bookSlug) {
433→      return new Response('Missing book parameter', { status: 400 })
434→    }
435→    const book = manifest.books.find((b) => b.slug === bookSlug)
436→    if (!book) {
437→      return new Response('Book not found', { status: 404 })
438→    }
439→    return handleCheckout(request, env, book)
440→  }
441→
442→  // POST /api/stripe-webhook
443→  if (pathname === '/api/stripe-webhook') {
444→    if (!env.STRIPE_SECRET_KEY) return missingEnvError('STRIPE_SECRET_KEY')
445→    if (!env.STRIPE_WEBHOOK_SECRET) return missingEnvError('STRIPE_WEBHOOK_SECRET')
446→    return handleWebhook(request, env)
447→  }
448→
449→  // GET /api/auth/callback?session_id=xxx (single-use post-checkout redirect)
450→  if (pathname === '/api/auth/callback') {
451→    if (!env.STRIPE_SECRET_KEY) return missingEnvError('STRIPE_SECRET_KEY')
452→    if (!env.COOKIE_SECRET) return missingEnvError('COOKIE_SECRET')
453→    return handleAuthCallback(request, env, manifest)
454→  }
455→
456→  // GET /api/auth/status?book=SLUG
457→  if (pathname === '/api/auth/status') {
458→    if (!env.COOKIE_SECRET) return missingEnvError('COOKIE_SECRET')
459→    const bookSlug = url.searchParams.get('book')
460→    if (!bookSlug) {
461→      return new Response(JSON.stringify({ authorized: false }), {
462→        headers: { 'Content-Type': 'application/json', ...NO_CACHE },
463→      })
464→    }
465→    const authorized = await isAuthorized(request, bookSlug, env.COOKIE_SECRET)
466→    return handleAuthStatus(request, env, authorized)
467→  }
468→
469→  // POST /api/auth/recover — sends magic link email
470→  if (pathname === '/api/auth/recover') {
471→    if (!env.COOKIE_SECRET) return missingEnvError('COOKIE_SECRET')
472→
473→    // Stricter rate limit for recover: 3 per 15 minutes per email
474→    try {
475→      const body = await request.clone().json() as { email?: string }
476→      const email = body.email?.trim().toLowerCase()
477→      if (email) {
478→        const emailBlocked = await rateLimit(env.PRESSY_KV, `recover:${email}`, 3, 15 * 60)
479→        if (emailBlocked) {
480→          return new Response('Too many requests', { status: 429, headers: NO_CACHE })
481→        }
482→      }
483→    } catch {
484→      // Body parse error will be handled by handleRecoverPurchase
485→    }
486→
487→    return handleRecoverPurchase(request, env, manifest, options.sendEmail)
488→  }
489→
490→  // GET /api/auth/verify?token=xxx — validates magic link, issues cookie
491→  if (pathname === '/api/auth/verify') {
492→    if (!env.COOKIE_SECRET) return missingEnvError('COOKIE_SECRET')
493→    return handleVerifyToken(request, env, manifest)
494→  }
495→
496→  return new Response('Not found', { status: 404 })
497→}
