107→function handleSWMessage(event: MessageEvent) {
108→  const { type } = event.data
109→
110→  if (type === 'CACHE_PROGRESS') {
111→    const { bookSlug, current, total } = event.data
112→    cacheProgress.value = { bookSlug, current, total }
113→  }
114→
115→  if (type === 'CACHE_COMPLETE') {
116→    const { bookSlug } = event.data
117→    cacheProgress.value = null
118→    const newCached = new Set(cachedBooks.value)
119→    newCached.add(bookSlug)
120→    cachedBooks.value = newCached
121→    persistCachedBooks()
122→  }
123→
124→  if (type === 'CACHE_STATUS') {
125→    const { cached } = event.data as { cached: string[] }
126→    const newCached = new Set<string>()
127→    for (const url of cached) {
128→      const match = url.match(/\/books\/([^/]+)/)
129→      if (match) {
130→        newCached.add(match[1])
131→      }
132→    }
133→    cachedBooks.value = newCached
134→    persistCachedBooks()
135→  }
136→
137→  if (type === 'CACHE_CLEARED') {
138→    const { bookSlug } = event.data
139→    const newCached = new Set(cachedBooks.value)
140→    newCached.delete(bookSlug)
141→    cachedBooks.value = newCached
142→    persistCachedBooks()
143→  }
144→}
