  }

  // Recover link toggle
  document.getElementById("recoverBtn").addEventListener("click", function() {
    document.getElementById("recoverForm").classList.toggle("visible");
    this.style.display = "none";
  });

  // Recover form submit
  document.getElementById("recoverForm").addEventListener("submit", function(e) {
    e.preventDefault();
    var email = document.getElementById("recoverEmail").value;
    var btn = document.getElementById("recoverSubmit");
    var msg = document.getElementById("recoverMsg");
    btn.disabled = true;
    btn.textContent = "Sending\\u2026";
    fetch("/api/auth/recover", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ email: email, book: bookSlug })
    })
    .then(function(r) {
      msg.classList.remove("hidden", "error", "success");
      if (r.ok) {
        msg.classList.add("success");
        msg.textContent = "Check your email for a recovery link.";
        document.getElementById("recoverForm").classList.remove("visible");
      } else {
        msg.classList.add("error");
        msg.textContent = "Something went wrong. Please try again.";
        btn.disabled = false;
        btn.textContent = "Send Recovery Link";
      }
    })
    .catch(function() {
      msg.classList.remove("hidden", "error", "success");
      msg.classList.add("error");
      msg.textContent = "Something went wrong. Please try again.";
      btn.disabled = false;
      btn.textContent = "Send Recovery Link";
    });
  });
})();
</script>
</body>
</html>`
}

function missingEnvError(...names: string[]): Response {
  const hint = names.map((n) => `wrangler pages secret put ${n}`).join(', ')
  return new Response(
    JSON.stringify({ error: `Missing required environment variable(s): ${names.join(', ')}. Set via: ${hint}` }),
    { status: 500, headers: { 'Content-Type': 'application/json', ...NO_CACHE } },
  )
}

// Route → allowed method(s) mapping
const ROUTE_METHODS: Record<string, string> = {
  '/api/checkout': 'GET',
  '/api/stripe-webhook': 'POST',
  '/api/auth/callback': 'GET',
  '/api/auth/status': 'GET',
  '/api/auth/recover': 'POST',
  '/api/auth/verify': 'GET',
}

async function handleApiRoute(
  request: Request,
  env: Env,
  pathname: string,
  url: URL,
  options: PressyMiddlewareOptions,
): Promise<Response> {
  // Method enforcement
  const allowedMethod = ROUTE_METHODS[pathname]
  if (allowedMethod && request.method !== allowedMethod) {
    return methodNotAllowed()
  }

  // Rate limiting for auth endpoints
  if (pathname.startsWith('/api/auth/')) {
    const ip = getClientIp(request)
    const blocked = await rateLimit(env.PRESSY_KV, `auth:${ip}`, 60, 60)
    if (blocked) {
      return new Response('Too many requests', { status: 429, headers: NO_CACHE })
    }
  }

  let manifest: PressyManifest
  try {
    manifest = await loadManifest(env)
  } catch {
    return new Response('Manifest not found', { status: 500 })
  }

  // GET /api/checkout?book=SLUG
  if (pathname === '/api/checkout') {
    if (!env.STRIPE_SECRET_KEY) return missingEnvError('STRIPE_SECRET_KEY')
    const bookSlug = url.searchParams.get('book')
    if (!bookSlug) {
      return new Response('Missing book parameter', { status: 400 })
    }
    const book = manifest.books.find((b) => b.slug === bookSlug)
    if (!book) {
      return new Response('Book not found', { status: 404 })
    }
    return handleCheckout(request, env, book)
  }

  // POST /api/stripe-webhook
  if (pathname === '/api/stripe-webhook') {
    if (!env.STRIPE_SECRET_KEY) return missingEnvError('STRIPE_SECRET_KEY')
    if (!env.STRIPE_WEBHOOK_SECRET) return missingEnvError('STRIPE_WEBHOOK_SECRET')
    return handleWebhook(request, env)
  }

  // GET /api/auth/callback?session_id=xxx (single-use post-checkout redirect)
  if (pathname === '/api/auth/callback') {
    if (!env.STRIPE_SECRET_KEY) return missingEnvError('STRIPE_SECRET_KEY')
    if (!env.COOKIE_SECRET) return missingEnvError('COOKIE_SECRET')
    return handleAuthCallback(request, env, manifest)
  }

  // GET /api/auth/status?book=SLUG
  if (pathname === '/api/auth/status') {
    if (!env.COOKIE_SECRET) return missingEnvError('COOKIE_SECRET')
    const bookSlug = url.searchParams.get('book')
    if (!bookSlug) {
      return new Response(JSON.stringify({ authorized: false }), {
        headers: { 'Content-Type': 'application/json', ...NO_CACHE },
      })
    }
    const authorized = await isAuthorized(request, bookSlug, env.COOKIE_SECRET)
    return handleAuthStatus(request, env, authorized)
  }

  // POST /api/auth/recover — sends magic link email
  if (pathname === '/api/auth/recover') {
    if (!env.COOKIE_SECRET) return missingEnvError('COOKIE_SECRET')

    // Stricter rate limit for recover: 3 per 15 minutes per email
    try {
      const body = await request.clone().json() as { email?: string }
      const email = body.email?.trim().toLowerCase()
      if (email) {
        const emailBlocked = await rateLimit(env.PRESSY_KV, `recover:${email}`, 3, 15 * 60)
        if (emailBlocked) {
          return new Response('Too many requests', { status: 429, headers: NO_CACHE })
        }
      }
    } catch {
      // Body parse error will be handled by handleRecoverPurchase
    }

    return handleRecoverPurchase(request, env, manifest, options.sendEmail)
  }

  // GET /api/auth/verify?token=xxx — validates magic link, issues cookie
  if (pathname === '/api/auth/verify') {
    if (!env.COOKIE_SECRET) return missingEnvError('COOKIE_SECRET')
    return handleVerifyToken(request, env, manifest)
  }

  return new Response('Not found', { status: 404 })
}

import type { CookiePayload, MagicLinkPayload } from './types.js'

const ENCODER = new TextEncoder()

/** Cookie lifetime: 1 year in seconds. */
export const COOKIE_MAX_AGE = 365 * 24 * 60 * 60

/** Magic link token lifetime: 15 minutes in seconds. */
export const MAGIC_LINK_TTL = 15 * 60

/** HKDF contexts for key separation. */
const COOKIE_KEY_CONTEXT = 'pressy-cookie-v1'
const MAGIC_KEY_CONTEXT = 'pressy-magic-v1'

/**
 * Derive a purpose-specific HMAC signing key from the master secret using HKDF.
 * This ensures cookie keys and magic-link keys are cryptographically separated.
 */
async function deriveKey(secret: string, context: string): Promise<CryptoKey> {
  const masterKey = await crypto.subtle.importKey(
    'raw',
    ENCODER.encode(secret),
    'HKDF',
    false,
    ['deriveBits'],
  )

  const derivedBits = await crypto.subtle.deriveBits(
    {
      name: 'HKDF',
      hash: 'SHA-256',
      salt: new Uint8Array(32), // fixed zero salt — context label provides separation
      info: ENCODER.encode(context),
    },
    masterKey,
    256,
  )

  return crypto.subtle.importKey(
    'raw',
    derivedBits,
    { name: 'HMAC', hash: 'SHA-256' },
    false,
    ['sign', 'verify'],
  )
}

function base64url(buffer: ArrayBuffer): string {
  const bytes = new Uint8Array(buffer)
  let binary = ''
  for (const b of bytes) binary += String.fromCharCode(b)
  return btoa(binary).replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '')
}

function base64urlDecode(str: string): Uint8Array {
  const padded = str.replace(/-/g, '+').replace(/_/g, '/') + '=='.slice(0, (4 - (str.length % 4)) % 4)
  const binary = atob(padded)
  const bytes = new Uint8Array(binary.length)
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i)
  return bytes
}

/**
 * Sign an arbitrary JSON payload with HMAC-SHA256.
 * Returns `base64url(payload).base64url(hmac)`.
 */
async function sign<T>(payload: T, key: CryptoKey): Promise<string> {
  const payloadJson = JSON.stringify(payload)
  const payloadB64 = base64url(ENCODER.encode(payloadJson).buffer as ArrayBuffer)
  const signature = await crypto.subtle.sign('HMAC', key, ENCODER.encode(payloadB64))
  return `${payloadB64}.${base64url(signature)}`
}

/**
 * Verify an HMAC-signed token and return the parsed payload.
 * Returns null if the signature is invalid, the token is malformed,
 * or the payload has an `exp` field that is in the past.
 */
async function verify<T extends { exp?: number }>(token: string, key: CryptoKey): Promise<T | null> {
  const dotIdx = token.indexOf('.')
  if (dotIdx === -1) return null

  const payloadB64 = token.slice(0, dotIdx)
  const sigB64 = token.slice(dotIdx + 1)

  try {
    const sigBytes = base64urlDecode(sigB64)
    const valid = await crypto.subtle.verify(
      'HMAC', key, sigBytes.buffer as ArrayBuffer, ENCODER.encode(payloadB64),
    )
    if (!valid) return null

    const payloadBytes = base64urlDecode(payloadB64)
    const payloadJson = new TextDecoder().decode(payloadBytes)
    const parsed = JSON.parse(payloadJson) as T

    // Reject expired tokens
    if (parsed.exp !== undefined && parsed.exp < Math.floor(Date.now() / 1000)) {
      return null
    }

    return parsed
  } catch {
    return null
  }
}

// ── Cookie helpers ───────────────────────────────────────────

export function cookieName(bookSlug: string): string {
  return `pressy-auth-${bookSlug}`
}

export async function signCookie(payload: CookiePayload, secret: string): Promise<string> {
  const key = await deriveKey(secret, COOKIE_KEY_CONTEXT)
  return sign(payload, key)
}

export async function verifyCookie(cookieValue: string, secret: string): Promise<CookiePayload | null> {
  const key = await deriveKey(secret, COOKIE_KEY_CONTEXT)
  return verify<CookiePayload>(cookieValue, key)
}

export function setCookieHeader(name: string, value: string): string {
  return `${name}=${value}; HttpOnly; Secure; SameSite=Lax; Path=/; Max-Age=${COOKIE_MAX_AGE}`
}

export function parseCookies(header: string): Record<string, string> {
  const cookies: Record<string, string> = {}
  for (const pair of header.split(';')) {
    const [key, ...rest] = pair.trim().split('=')
    if (key) cookies[key.trim()] = rest.join('=').trim()
  }
  return cookies
}

// ── Magic link token helpers ─────────────────────────────────

export async function signMagicToken(payload: MagicLinkPayload, secret: string): Promise<string> {
  const key = await deriveKey(secret, MAGIC_KEY_CONTEXT)
  return sign(payload, key)
}

export async function verifyMagicToken(token: string, secret: string): Promise<MagicLinkPayload | null> {
  const key = await deriveKey(secret, MAGIC_KEY_CONTEXT)
  return verify<MagicLinkPayload>(token, key)
}

import Stripe from 'stripe'
import type { Env, PressyBookManifest, PurchaseRecord, EmailSender } from './types.js'
import { signCookie, setCookieHeader, cookieName, COOKIE_MAX_AGE, signMagicToken, verifyMagicToken, MAGIC_LINK_TTL } from './auth.js'
import { buildMagicLinkEmail } from './email.js'

const NO_CACHE = { 'Cache-Control': 'no-store' }
const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/
const BOOK_SLUG_RE = /^[a-z0-9]+(?:-[a-z0-9]+)*$/

async function sha256hex(input: string): Promise<string> {
  const data = new TextEncoder().encode(input)
  const hash = await crypto.subtle.digest('SHA-256', data)
  return Array.from(new Uint8Array(hash)).map((b) => b.toString(16).padStart(2, '0')).join('')
}

function getStripe(secretKey: string): Stripe {
  return new Stripe(secretKey, { apiVersion: '2025-02-24.acacia' })
}

function getBaseUrl(request: Request): string {
  const url = new URL(request.url)
  return `${url.protocol}//${url.host}`
}

function nowEpoch(): number {
  return Math.floor(Date.now() / 1000)
}

// ── Checkout ─────────────────────────────────────────────────

export async function handleCheckout(
  request: Request,
  env: Env,
  book: PressyBookManifest,
): Promise<Response> {
  const stripe = getStripe(env.STRIPE_SECRET_KEY)
  const baseUrl = getBaseUrl(request)

  if (!book.paywall?.stripePriceId) {
    return new Response('Book has no Stripe product configured', { status: 400 })
  }

  const session = await stripe.checkout.sessions.create({
    mode: 'payment',
    line_items: [{ price: book.paywall.stripePriceId, quantity: 1 }],
    success_url: `${baseUrl}/api/auth/callback?session_id={CHECKOUT_SESSION_ID}`,
    cancel_url: `${baseUrl}/books/${book.slug}/`,
    metadata: { bookSlug: book.slug },
  })

  return Response.redirect(session.url!, 303)
}

// ── Webhook ──────────────────────────────────────────────────

export async function handleWebhook(
  request: Request,
  env: Env,
): Promise<Response> {
  const stripe = getStripe(env.STRIPE_SECRET_KEY)
  const body = await request.text()
  const signature = request.headers.get('stripe-signature')

  if (!signature) {
    return new Response('Missing stripe-signature header', { status: 400 })
  }

  let event: Stripe.Event
  try {
    event = await stripe.webhooks.constructEventAsync(body, signature, env.STRIPE_WEBHOOK_SECRET)
  } catch {
    return new Response('Webhook signature verification failed', { status: 400 })
  }

  if (event.type === 'checkout.session.completed') {
    const session = event.data.object as Stripe.Checkout.Session
    const bookSlug = session.metadata?.bookSlug
    const email = session.customer_details?.email

    if (bookSlug && email) {
      const record: PurchaseRecord = {
        sessionId: session.id,
        email,
        bookSlug,
        amount: session.amount_total || 0,
        purchasedAt: new Date().toISOString(),
      }

      await env.PRESSY_KV.put(
        `purchase:${email}:${bookSlug}`,
        JSON.stringify(record),
        { expirationTtl: 5 * 365 * 24 * 60 * 60 }, // 5 years
      )
    }
  }

  return new Response('ok', { status: 200 })
}

// ── Auth callback (post-checkout redirect) ───────────────────

export async function handleAuthCallback(
  request: Request,
  env: Env,
  manifest: { books: PressyBookManifest[] },
): Promise<Response> {
  const url = new URL(request.url)
  const sessionId = url.searchParams.get('session_id')

  if (!sessionId) {
    return new Response('Missing session_id', { status: 400, headers: NO_CACHE })
  }

  // Single-use: reject if this session_id has already been consumed
  const consumedKey = `callback-consumed:${sessionId}`
  const alreadyConsumed = await env.PRESSY_KV.get(consumedKey)
  if (alreadyConsumed) {
    return new Response('This link has already been used', { status: 410, headers: NO_CACHE })
  }

  const stripe = getStripe(env.STRIPE_SECRET_KEY)
  const session = await stripe.checkout.sessions.retrieve(sessionId)

  if (session.payment_status !== 'paid') {
    return new Response('Payment not completed', { status: 402, headers: NO_CACHE })
  }

  const bookSlug = session.metadata?.bookSlug
  const email = session.customer_details?.email
  if (!bookSlug || !email) {
    return new Response('Invalid session metadata', { status: 400, headers: NO_CACHE })
  }

  const book = manifest.books.find((b) => b.slug === bookSlug)
  if (!book) {
    return new Response('Book not found', { status: 404, headers: NO_CACHE })
  }

  // Mark session as consumed (keep for 24h — long enough to prevent replay)
  await env.PRESSY_KV.put(consumedKey, '1', { expirationTtl: 24 * 60 * 60 })

  // Record purchase in KV (in case webhook hasn't fired yet)
  const record: PurchaseRecord = {
    sessionId: session.id,
    email,
    bookSlug,
    amount: session.amount_total || 0,
    purchasedAt: new Date().toISOString(),
  }
  await env.PRESSY_KV.put(
    `purchase:${email}:${bookSlug}`,
    JSON.stringify(record),
    { expirationTtl: 5 * 365 * 24 * 60 * 60 },
  )

  // Sign and set auth cookie with expiration
  const cookieValue = await signCookie(
    {
      book: bookSlug,
      email,
      purchasedAt: record.purchasedAt,
      sessionId,
      exp: nowEpoch() + COOKIE_MAX_AGE,
    },
    env.COOKIE_SECRET,
  )

  // Redirect to the book home page so the user can click "Continue Reading"
  const redirectPath = `/books/${bookSlug}/`

  return new Response(null, {
    status: 302,
    headers: {
      Location: redirectPath,
      'Set-Cookie': setCookieHeader(cookieName(bookSlug), cookieValue),
      ...NO_CACHE,
    },
  })
}

// ── Auth status check ────────────────────────────────────────

export async function handleAuthStatus(
  _request: Request,
  _env: Env,
  authorized: boolean,
): Promise<Response> {
  return new Response(JSON.stringify({ authorized }), {
    headers: { 'Content-Type': 'application/json', ...NO_CACHE },
  })
}

// ── Recover purchase (sends magic link) ──────────────────────

export async function handleRecoverPurchase(
  request: Request,
  env: Env,
  manifest: { books: PressyBookManifest[] },
  sendEmail?: EmailSender,
): Promise<Response> {
  // Must be POST — state-changing operation
  if (request.method !== 'POST') {
    return new Response('Method not allowed', { status: 405, headers: NO_CACHE })
  }

  let body: { email?: string; book?: string }
  try {
    body = await request.json()
  } catch {
    return new Response(JSON.stringify({ error: 'Invalid JSON body' }), {
      status: 400,
      headers: { 'Content-Type': 'application/json', ...NO_CACHE },
    })
  }

  const email = body.email?.trim().toLowerCase()
  const bookSlug = body.book

  if (!email || !bookSlug) {
    return new Response(JSON.stringify({ error: 'Missing email or book' }), {
      status: 400,
      headers: { 'Content-Type': 'application/json', ...NO_CACHE },
    })
  }

  if (!EMAIL_RE.test(email)) {
    return new Response(JSON.stringify({ error: 'Invalid email format' }), {
      status: 400,
      headers: { 'Content-Type': 'application/json', ...NO_CACHE },
    })
  }

  if (!BOOK_SLUG_RE.test(bookSlug)) {
    return new Response(JSON.stringify({ error: 'Invalid book slug' }), {
      status: 400,
      headers: { 'Content-Type': 'application/json', ...NO_CACHE },
    })
  }

  const book = manifest.books.find((b) => b.slug === bookSlug)
  if (!book) {
    return new Response(JSON.stringify({ error: 'Book not found' }), {
      status: 400,
      headers: { 'Content-Type': 'application/json', ...NO_CACHE },
    })
  }

  // Look up purchase — but DON'T reveal whether the email exists.
  // Always return the same success message to prevent email enumeration.
  const record = await env.PRESSY_KV.get(`purchase:${email}:${bookSlug}`)

  if (record) {
    // Purchase exists — send magic link email
    const baseUrl = getBaseUrl(request)
    const token = await signMagicToken(
      { email, bookSlug, exp: nowEpoch() + MAGIC_LINK_TTL },
      env.COOKIE_SECRET,
    )
    const verifyUrl = `${baseUrl}/api/auth/verify?token=${encodeURIComponent(token)}`

    const book = manifest.books.find((b) => b.slug === bookSlug)
    const bookTitle = book?.paywall?.price
      ? bookSlug // We don't have the book title in the manifest, use slug
      : undefined

    if (!sendEmail) {
      return new Response(JSON.stringify({ error: 'Email sending is not configured' }), {
        status: 500,
        headers: { 'Content-Type': 'application/json', ...NO_CACHE },
      })
    }

    try {
      await sendEmail({
        to: email,
        subject: 'Recover your book purchase',
        html: buildMagicLinkEmail(verifyUrl, bookTitle),
        verifyUrl,
        bookTitle,
      })
    } catch {
      return new Response(JSON.stringify({ error: 'Failed to send email. Please try again.' }), {
        status: 500,
        headers: { 'Content-Type': 'application/json', ...NO_CACHE },
      })
    }
  }

  // Same response regardless of whether purchase was found (anti-enumeration)
  return new Response(
    JSON.stringify({ sent: true, message: 'If a purchase exists for this email, a recovery link has been sent.' }),
    { headers: { 'Content-Type': 'application/json', ...NO_CACHE } },
  )
}

// ── Verify magic link token ──────────────────────────────────

export async function handleVerifyToken(
  request: Request,
  env: Env,
  manifest: { books: PressyBookManifest[] },
): Promise<Response> {
  const url = new URL(request.url)
  const token = url.searchParams.get('token')

  if (!token) {
    return new Response('Missing token', { status: 400, headers: NO_CACHE })
  }

  // Verify HMAC signature and expiration
  const payload = await verifyMagicToken(token, env.COOKIE_SECRET)
  if (!payload) {
    return new Response('Invalid or expired link. Please request a new one.', {
      status: 403,
      headers: NO_CACHE,
    })
  }

  // Validate payload fields
  if (!EMAIL_RE.test(payload.email) || !BOOK_SLUG_RE.test(payload.bookSlug)) {
    return new Response('Invalid token payload', { status: 400, headers: NO_CACHE })
  }

  if (!manifest.books.find((b) => b.slug === payload.bookSlug)) {
    return new Response('Book not found', { status: 400, headers: NO_CACHE })
  }

  // Single-use: prevent replay (hash full token to avoid prefix collisions)
  const tokenHash = await sha256hex(token)
  const consumedKey = `magic-consumed:${tokenHash}`
  const alreadyConsumed = await env.PRESSY_KV.get(consumedKey)
  if (alreadyConsumed) {
    return new Response('This link has already been used.', { status: 410, headers: NO_CACHE })
  }

  // Confirm the purchase still exists in KV
  const record = await env.PRESSY_KV.get(`purchase:${payload.email}:${payload.bookSlug}`)
  if (!record) {
    return new Response('No purchase found', { status: 404, headers: NO_CACHE })
  }

  const purchase: PurchaseRecord = JSON.parse(record)
  const book = manifest.books.find((b) => b.slug === payload.bookSlug)

  // Mark token as consumed (keep for the token's TTL — 15 min is plenty)
  await env.PRESSY_KV.put(consumedKey, '1', { expirationTtl: MAGIC_LINK_TTL })

  // Issue auth cookie
  const cookieValue = await signCookie(
    {
      book: payload.bookSlug,
      email: payload.email,
      purchasedAt: purchase.purchasedAt,
      sessionId: purchase.sessionId,
      exp: nowEpoch() + COOKIE_MAX_AGE,
    },
    env.COOKIE_SECRET,
  )

  // Redirect to the book home page so the user can click "Continue Reading"
  const redirectPath = `/books/${payload.bookSlug}/`

  return new Response(null, {
    status: 302,
    headers: {
      Location: redirectPath,
      'Set-Cookie': setCookieHeader(cookieName(payload.bookSlug), cookieValue),
      ...NO_CACHE,
    },
  })
}

/// <reference lib="webworker" />
import { precacheAndRoute, cleanupOutdatedCaches } from 'workbox-precaching'
import { registerRoute, NavigationRoute, Route } from 'workbox-routing'
import { NetworkFirst, CacheFirst, StaleWhileRevalidate } from 'workbox-strategies'
import { ExpirationPlugin } from 'workbox-expiration'
import {
  isBookChapterNavigation,
  needsTrailingSlashRedirect,
  normalizeCacheUrl,
  prepareResponseForCache,
} from './sw-logic'

declare const self: ServiceWorkerGlobalScope

const OFFLINE_CACHE = 'pressy-offline'
// Use the SW's own location to derive the base path for offline.html,
// so it works on subpath deployments (e.g. /pressy/pr-preview/pr-1/sw.js)
const SW_BASE = new URL('./', (self as unknown as ServiceWorkerGlobalScope).location.href).pathname
const OFFLINE_URL = `${SW_BASE}offline.html`
const BOOK_CACHE = 'pressy-offline-books'

// Precache all static assets (injected by build tool)
precacheAndRoute(self.__WB_MANIFEST, {
  ignoreURLParametersMatching: [/^page$/],
})

// Clean up old caches
cleanupOutdatedCaches()

// Cache the offline fallback page on install
self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(OFFLINE_CACHE).then((cache) => cache.add(OFFLINE_URL))
  )
  self.skipWaiting()
})

self.addEventListener('activate', (event) => {
  event.waitUntil(self.clients.claim())
})

// Plugin that respects Cache-Control: no-store (workbox ignores it by default).
// This prevents paywall/auth-gated responses from polluting the SW cache.
const respectNoStore = {
  cacheWillUpdate: async ({ response }: { response: Response }) => {
    const cc = response.headers.get('Cache-Control')
    if (cc && cc.includes('no-store')) return null
    return response
  },
}

// Navigation: NetworkFirst with offline fallback
const navigationHandler = new NetworkFirst({
  cacheName: 'pressy-pages',
  networkTimeoutSeconds: 3,
  plugins: [respectNoStore],
})

// Offline-cached book chapters: try the book cache first,
// then fall through to the normal navigation handler.
// Registered BEFORE the general NavigationRoute so book chapter
// URLs are checked against the offline book cache first.
// ignoreSearch: true so ?page=last (backward chapter nav) matches
// the cached response for the base URL.
registerRoute(
  new Route(
    ({ request, url }) => isBookChapterNavigation(url.pathname, request.mode),
    async (params) => {
      // Redirect non-trailing-slash URLs so relative asset paths in the
      // HTML (e.g. ../../../assets/foo.js) resolve against the correct
      // directory. Without the slash, the browser uses the parent path.
      if (needsTrailingSlashRedirect(params.url.pathname)) {
        const dest = new URL(params.url.href)
        dest.pathname += '/'
        return Response.redirect(dest.href, 302)
      }

      // Check offline book cache (trailing-slash keys)
      const bookCache = await caches.open(BOOK_CACHE)
      const cached = await bookCache.match(params.request, { ignoreSearch: true })
      if (cached) return cached

      // Fall through to network
      try {
        return await navigationHandler.handle(params)
      } catch {
        // Network failed — try the general navigation cache with ignoreSearch
        // so ?page=last variants still hit cached chapter pages
        const pagesCache = await caches.open('pressy-pages')
        const pagesCached = await pagesCache.match(params.request, { ignoreSearch: true })
        if (pagesCached) return pagesCached

        const cache = await caches.open(OFFLINE_CACHE)
        const fallback = await cache.match(OFFLINE_URL)
        return fallback || Response.error()
      }
    }
  )
)

// General navigation: NetworkFirst with offline fallback
registerRoute(
  new NavigationRoute(async (params) => {
    try {
      return await navigationHandler.handle(params)
    } catch {
      // Network failed — try offline book cache and pressy-pages with
      // ignoreSearch so ?page=last (backward chapter nav) still resolves
      const bookCache = await caches.open(BOOK_CACHE)
      const bookCached = await bookCache.match(params.request, { ignoreSearch: true })
      if (bookCached) return bookCached

      const pagesCache = await caches.open('pressy-pages')
      const pagesCached = await pagesCache.match(params.request, { ignoreSearch: true })
      if (pagesCached) return pagesCached

      // Last resort — serve offline fallback
      const cache = await caches.open(OFFLINE_CACHE)
      const fallback = await cache.match(OFFLINE_URL)
      return fallback || Response.error()
    }
  })
)

// Cache images with CacheFirst strategy (exclude PWA icons — they're
// updated on each deploy and should not be stuck behind a stale cache)
registerRoute(
  ({ request, url }) =>
    request.destination === 'image' &&
    !url.pathname.endsWith('/icon-192.png') &&
    !url.pathname.endsWith('/icon-512.png') &&
    !url.pathname.endsWith('/favicon.png'),
  new CacheFirst({
    cacheName: 'pressy-images',
    plugins: [
      new ExpirationPlugin({
        maxEntries: 100,
        maxAgeSeconds: 60 * 60 * 24 * 30, // 30 days
      }),
    ],
  })
)

// Cache fonts with CacheFirst strategy
registerRoute(
  ({ request }) => request.destination === 'font',
  new CacheFirst({
    cacheName: 'pressy-fonts',
    plugins: [
      new ExpirationPlugin({
        maxEntries: 20,
        maxAgeSeconds: 60 * 60 * 24 * 365, // 1 year
      }),
    ],
  })
)

// Cache CSS and JS with NetworkFirst so deploys are picked up immediately.
// Vite hashes filenames so old URLs are never re-requested — the main
// benefit of caching here is offline support, not speed.
registerRoute(
  ({ request }) =>
    request.destination === 'style' || request.destination === 'script',
  new NetworkFirst({
    cacheName: 'pressy-static',
    networkTimeoutSeconds: 3,
    plugins: [respectNoStore],
  })
)

// Message handler for manual cache operations
self.addEventListener('message', async (event) => {
  if (event.data?.type === 'CACHE_BOOK') {
    const { bookSlug, urls } = event.data
    const cache = await caches.open(BOOK_CACHE)
    let completed = 0

    for (const url of urls) {
      try {
        const response = await fetch(url)
        if (response.ok) {
          // Strip the redirected flag — navigation requests reject
          // already-followed redirect responses from the cache.
          const clean = prepareResponseForCache(response)
          // Normalize cache key to trailing-slash so it matches
          // redirected navigation requests (e.g. /chapter-2/)
          const cacheUrl = normalizeCacheUrl(url)
          await cache.put(cacheUrl, clean)
        }
      } catch (err) {
        console.error(`Failed to cache ${url}:`, err)
      }

      completed++
      // Report progress back to client
      event.source?.postMessage({
        type: 'CACHE_PROGRESS',
        bookSlug,
        current: completed,
        total: urls.length,
      })
    }

    // Notify client that caching is complete
    event.source?.postMessage({ type: 'CACHE_COMPLETE', bookSlug, urls })
  }

  if (event.data?.type === 'GET_CACHE_STATUS') {
    const { urls } = event.data
    const cache = await caches.open(BOOK_CACHE)
    const cached: string[] = []

    for (const url of urls) {
      // Normalize to trailing-slash to match CACHE_BOOK keys
      const matchUrl = normalizeCacheUrl(url)
      const response = await cache.match(matchUrl)
      if (response) {
        cached.push(url)
      }
    }

    event.source?.postMessage({ type: 'CACHE_STATUS', cached })
  }

  if (event.data?.type === 'CLEAR_BOOK_CACHE') {
    const { bookSlug } = event.data
    const cache = await caches.open(BOOK_CACHE)
    const keys = await cache.keys()

    for (const request of keys) {
      if (request.url.includes(`/books/${bookSlug}`)) {
        await cache.delete(request)
      }
    }

    event.source?.postMessage({ type: 'CACHE_CLEARED', bookSlug })
  }

  if (event.data?.type === 'INVALIDATE_BOOK_PAGES') {
    const { bookSlug } = event.data
    const cacheNames = ['pressy-pages', 'pressy-static']
    for (const name of cacheNames) {
      const cache = await caches.open(name)
      const keys = await cache.keys()
      for (const request of keys) {
        if (request.url.includes(`/books/${bookSlug}`)) {
          await cache.delete(request)
        }
      }
    }
    event.source?.postMessage({ type: 'BOOK_PAGES_INVALIDATED', bookSlug })
  }

  if (event.data?.type === 'SKIP_WAITING') {
    self.skipWaiting()
  }
})

