/** Generates the offline fallback HTML page. */
export function generateOfflinePage(siteTitle: string): string {
  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Offline | ${siteTitle}</title>
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }

    body {
      font-family: Georgia, 'Times New Roman', serif;
      display: flex;
      align-items: center;
      justify-content: center;
      min-height: 100vh;
      padding: 2rem;
      background: #fafafa;
      color: #1a1a1a;
    }

    .offline-container {
      text-align: center;
      max-width: 420px;
    }

    .offline-icon {
      width: 64px;
      height: 64px;
      margin: 0 auto 1.5rem;
      color: #999;
    }

    h1 {
      font-size: 1.5rem;
      margin-bottom: 0.75rem;
    }

    p {
      color: #666;
      line-height: 1.6;
      margin-bottom: 1.5rem;
    }

    button {
      font-family: inherit;
      font-size: 1rem;
      padding: 0.75rem 1.5rem;
      background: #1a1a1a;
      color: #fff;
      border: none;
      border-radius: 0.5rem;
      cursor: pointer;
      transition: background 0.15s;
    }

    button:hover { background: #333; }

    @media (prefers-color-scheme: dark) {
      body { background: #1a1a1a; color: #e5e5e5; }
      p { color: #999; }
      .offline-icon { color: #666; }
      button { background: #e5e5e5; color: #1a1a1a; }
      button:hover { background: #ccc; }
    }
  </style>
</head>
<body>
  <div class="offline-container">
    <svg class="offline-icon" viewBox="0 0 24 24" fill="currentColor">
      <path d="M23.64 7c-.45-.34-4.93-4-11.64-4-1.5 0-2.89.19-4.15.48L18.18 13.8 23.64 7zM3.41 1.31L2 2.72l2.05 2.05C1.91 5.76.59 6.82.36 7L12 21.5l3.91-4.87 3.32 3.32 1.41-1.41L3.41 1.31z"/>
    </svg>
    <h1>You\u2019re offline</h1>
    <p>This page isn\u2019t available right now. If you\u2019ve previously downloaded this book for offline reading, try navigating to it directly.</p>
    <button onclick="window.location.reload()">Try again</button>
  </div>
</body>
</html>`
}

